sp_page.css:
/* 2.6.0 | 2021-03-11 | mmcc | STRY0092273 DTLV – Optimize Print of the Dynamic Tree Level View */
/* 2.6.0 | 2021-03-25 | mmcc | STRY0096101 Tree Level Print Report: Requests */
/* 2.7.0 | 2021-06-29 | mmcc | STRY0104015 DTLV - HTML fields are being trimmed to 4000 characters (General Objective Field and the Instructions fields) */
/* 2.8.0 | 2022-04-04 | raj  | STRY0119590 Task Form Page Layout- Layout: DTLV */
.navbar-nav {     float:none;     margin:0 auto;     display: block;     text-align: center; } .navbar-nav > li {     display: inline-block;     float:none; }

/* 2.8.1 | 2022-11-25 | raj | DFCT0011436 - On the "DTLV" view click on Subtasks > click a row with subtask > click Subtasks tab > NO rows are shown */
/* Tasker Data Table */
.v1fe908a64fc71300d236eb118110c78a {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* 2.8.1 | 2022-12-02 | mmcc | DFCT0011419 - On the "Three Column" view  click on the Subtasks > click a row with  subtask > click Subtasks tab > NO rows are shown */
/* Tasker Attachments */
.v5a5d0f5cdb81b300bb8ee536ca96193f {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* 2.8.1 | 2022-12-02 | mmcc | DFCT0011419 - On the "Three Column" view  click on the Subtasks */
/* flex sp-widget for DocInt List */
.v6dedb22adb9fdb0069d100b5ca96195f {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* 2.8.5 | 2023-06-16 | mmcc | DFCT0012012 - In a Modal Scheduled OOO and View scheduling history are not showing any rows; added  */
/* Tasker User Profile */
.v7e13daf81bb94550888aebde6e4bcb47  {
  display: flex;
  flex-grow: 1;
  /* Do not center for OOO Schedule justify-content: center; */
}

/* 2.8.5 | 2023-06-16 | mmcc | DFCT0012012 - In a Modal Scheduled OOO and View scheduling history are not showing any rows; added */
/* Out of Office */ 
.vb15780ab1b8f9910e75655f5624bcb9c {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

/* 2.8.5 | 2023-06-16 | mmcc | DFCT0012012 - In a Modal Scheduled OOO and View scheduling history are not showing any rows; added */
/* Scheduled Out of Office */ 
.v531dae861b43d510e75655f5624bcb60 {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

@media print {
  /* targets the row the Search box is on */
  div.breadcrumbs-container { 
    display: none;
  }
  
  /* targets the Widget named: Tasker States Progress Bar */
  div.progress-bar[title~="0.000%"] {
    display: none;
  }
  
  #summary-card-print {
    break-inside: avoid-page;
    orphans: 2;
    widows: 2;
    width: 100%;
  }
  
  .print-better {
    break-inside: avoid;
    orphans: 2;
    widows: 2;
    width: 100%;
  }
  
  /* 2.7.0 | 2021-06-29 | mmcc | STRY0104015 DTLV - HTML fields are being trimmed */
  .print-better-no-break {
    orphans: 4;
    widows: 4;
    width: 100%;
  }

  /* 2.6.0 | 2021-03-25 | mmcc | STRY0096101 Tree Level Print Report: Requests */
  /* Pasted the below Bootstrap 3.3.6 selectors, removed all but padding and set it to 4px instead of 8; Helps Requests table not have a scroll bar in Portrait Letter */
  .table  > thead  > tr  > th, .table  > thead  > tr  > td, .table  > tbody  > tr  > th, .table  > tbody  > tr  > td, .table  > tfoot  > tr  > th, .table  > tfoot  > tr  > td {
	padding: 4px;
}
  
  /* copy of Bootstrap 3.3.6, without these, Subtasks by Status and Summary Card are not looking very good */
  .col-xs-1, .col-sm-1, .col-md-1, .col-lg-1, .col-xs-2, .col-sm-2, .col-md-2, .col-lg-2, .col-xs-3, .col-sm-3, .col-md-3, .col-lg-3, .col-xs-4, .col-sm-4, .col-md-4, .col-lg-4, .col-xs-5, .col-sm-5, .col-md-5, .col-lg-5, .col-xs-6, .col-sm-6, .col-md-6, .col-lg-6, .col-xs-7, .col-sm-7, .col-md-7, .col-lg-7, .col-xs-8, .col-sm-8, .col-md-8, .col-lg-8, .col-xs-9, .col-sm-9, .col-md-9, .col-lg-9, .col-xs-10, .col-sm-10, .col-md-10, .col-lg-10, .col-xs-11, .col-sm-11, .col-md-11, .col-lg-11, .col-xs-12, .col-sm-12, .col-md-12, .col-lg-12 {
    position: relative;
    min-height: 1px;
    padding-right: 15px;
    padding-left: 15px;
  }
  .col-md-1, .col-md-2, .col-md-3, .col-md-4, .col-md-5, .col-md-6, .col-md-7, .col-md-8, .col-md-9, .col-md-10, .col-md-11, .col-md-12 {
    float: left;
  }
  .col-md-12 {
    width: 100%;
  }
  .col-md-11 {
    width: 91.66666667%;
  }
  .col-md-10 {
    width: 83.33333333%;
  }
  .col-md-9 {
    width: 75%;
  }
  .col-md-8 {
    width: 66.66666667%;
  }
  .col-md-7 {
    width: 58.33333333%;
  }
  .col-md-6 {
    width: 50%;
  }
  .col-md-5 {
    width: 41.66666667%;
  }
  .col-md-4 {
    width: 33.33333333%;
  }
  .col-md-3 {
    width: 25%;
  }
  .col-md-2 {
    width: 16.66666667%;
  }
  .col-md-1 {
    width: 8.33333333%;
  }
  
}

.content {
     margin-left: 25px !important;
     margin-right: 30px !important;
}
